class DownloadFile:
    def __init__(self):
        self.url = "https://gitee.com/Rookie-wb-WH/some_useless_files/raw/master/sofile/"
        self.fileName = "pyCodeProtect"
        self.supportPyVer = [10, 11, 12, 13]
        self.supportOS = ["Linux"]
        self.supportArch = ["x86_64", "aarch64"]
        self.v = sys.version_info
        self.os_type = platform.system()
        self.arch = platform.machine()

    def getSystemInfo(self):
        if self.arch == "AMD64": self.arch = "x86_64"
        if self.arch == "ARM64": self.arch = "aarch64"
        result = {
            "pyVersion": f"{self.v.major}.{self.v.minor}.{self.v.micro}",
            "OS": self.os_type,
            "arch": self.arch,
        }
        if self.v.minor not in self.supportPyVer:
            return False, f"不支持Python版本: {result['pyVersion']}"
        if result["OS"] not in self.supportOS:
            return False, f"不支持操作系统: {result['OS']}"
        if result["arch"] not in self.supportArch:
            return False, f"不支持CPU架构: {result['arch']}"
        return True, result
    
    async def download(self):
        check, result = self.getSystemInfo()
        if not check:
            print(result)
            return
        
        fileName = f'{self.fileName}_3{self.v.minor}_{result["arch"]}.so'
        command = ['curl', '-#', '-o', 'pyCodeProtect.so', '-w', '%{http_code}', self.url  + fileName]
        
        process = await asyncio.create_subprocess_exec(
            *command,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE
        )
        
        stdout, stderr = await process.communicate()
        
        output = stdout.decode().strip()
        error_output = stderr.decode().strip()

        http_code = int(output.split('\r')[-1])

        if process.returncode == 0 and http_code == 200:
            savePath = os.path.join(os.path.dirname(__file__), 'pyCodeProtect.so')
            file_size = os.path.getsize('pyCodeProtect.so')
            print(f"文件大小: {file_size/1024:.2f} KB")
            print(f"下载路径: {savePath}")
            return True
        else:
            print(f"下载失败，{error_output}, 错误码: {process.returncode}")
            if os.path.exists('pyCodeProtect.so'):
                os.remove('pyCodeProtect.so')
            return False

async def execCode(code):
    try:
        import pyCodeProtect
        pyCodeProtect.run(code)
    except Exception as e:
        print(f"执行出错: {e}")

async def main():
    if os.path.exists('pyCodeProtect.so'):
        print('本地发现 pyCodeProtect.so 文件，准备执行')
        await execCode(pythonCode)
        return

    print('本地未发现 pyCodeProtect.so 文件，准备下载')
    run = DownloadFile()
    if await run.download():
        await execCode(pythonCode)


if __name__ == "__main__":
    asyncio.run(main())
